import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import UploadZone from '../components/UploadZone';
import LoadingSpinner from '../components/LoadingSpinner';
import { predictBreed } from '../services/api';
import './HomePage.css';

export default function HomePage() {
  const [file, setFile]         = useState(null);
  const [preview, setPreview]   = useState(null);
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState('');
  const navigate = useNavigate();

  // Called by UploadZone when user selects a file
  const handleFileSelected = useCallback((selectedFile) => {
    setError('');
    setFile(selectedFile);
    // Create a local object URL for instant preview
    if (preview) URL.revokeObjectURL(preview); // clean up previous
    setPreview(URL.createObjectURL(selectedFile));
  }, [preview]);

  const handleSubmit = async () => {
    if (!file) {
      setError('Please select an image before submitting.');
      return;
    }
    setError('');
    setLoading(true);

    try {
      const result = await predictBreed(file);
      // Pass result + preview URL to the result page via router state
      navigate('/result', {
        state: { result, previewUrl: preview },
      });
    } catch (err) {
      const msg =
        err?.response?.data?.error ||
        'Something went wrong. Is the backend running?';
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="home-page">
      {loading && <LoadingSpinner message="Identifying breed…" />}

      {/* ── Hero ── */}
      <section className="hero container">
        <div className="hero-badge fade-up">🐄 AI-Powered Recognition</div>
        <h1 className="hero-title fade-up-2">
          Identify Any<br />
          <span className="hero-title-accent">Cattle Breed</span>
          <br />Instantly
        </h1>
        <p className="hero-subtitle fade-up-3">
          Upload a photo of any cow or buffalo and our AI will identify
          its breed with detailed production stats and characteristics.
        </p>
      </section>

      {/* ── Upload card ── */}
      <section className="upload-section container fade-up-4">
        <div className="upload-card card">
          <div className="upload-card-header">
            <h2 className="upload-card-title">Upload Image</h2>
            <p className="upload-card-sub">
              Supports Gir, Sahiwal, Murrah, Holstein Friesian &amp; more
            </p>
          </div>

          <UploadZone onFileSelected={handleFileSelected} preview={preview} />

          {file && (
            <div className="file-meta">
              <span className="file-meta-icon">📎</span>
              <span className="file-meta-name">{file.name}</span>
              <span className="file-meta-size">
                ({(file.size / 1024).toFixed(1)} KB)
              </span>
              <button
                className="file-meta-clear"
                onClick={() => { setFile(null); setPreview(null); setError(''); }}
                aria-label="Remove file"
              >
                ✕
              </button>
            </div>
          )}

          {error && (
            <div className="submit-error" role="alert">
              ⚠ {error}
            </div>
          )}

          <button
            className="btn-primary submit-btn"
            onClick={handleSubmit}
            disabled={!file || loading}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
              stroke="currentColor" strokeWidth="2.5">
              <path d="M9 18l6-6-6-6"/>
            </svg>
            Identify Breed
          </button>
        </div>
      </section>

      {/* ── How it works ── */}
      <section className="how-section container">
        <h3 className="how-title">How It Works</h3>
        <div className="how-steps">
          {[
            { n: '01', title: 'Upload',   desc: 'Drop or select any clear photo of the animal.' },
            { n: '02', title: 'Analyse',  desc: 'Our model examines coat, body shape, and horn profile.' },
            { n: '03', title: 'Discover', desc: 'Get breed name, confidence, and full production stats.' },
          ].map(step => (
            <div className="how-step" key={step.n}>
              <span className="how-step-num">{step.n}</span>
              <h4 className="how-step-title">{step.title}</h4>
              <p className="how-step-desc">{step.desc}</p>
            </div>
          ))}
        </div>
      </section>
    </main>
  );
}
